using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// ── Source-gen context that only knows about Person ──────────────
// This deliberately omits Order, so TryGetTypeInfo will return false for it.
var options = new JsonSerializerOptions { TypeInfoResolver = AppJsonContext.Default };

// ─── 1. Strongly-typed retrieval: JsonTypeInfo<T> ────────────────
// GetTypeInfo returns the non-generic base; cast to the generic form.
var personInfo = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine($"Got JsonTypeInfo<Person>  –  {personInfo.Properties.Count} properties: " +
    string.Join(", ", personInfo.Properties.Select(p => p.Name)));

// Use it to round-trip an object through the typed overloads:
var json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
var alice = JsonSerializer.Deserialize(json, personInfo)!;
Console.WriteLine($"Round-tripped: {alice}  (json: {json})");

// ─── 2. Probe without throwing: TryGetTypeInfo ───────────────────
// Person IS in the context → succeeds
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
    Console.WriteLine($"\n✔ Metadata available for {found!.Type.Name}");

// Order is NOT in the context → returns false, no exception
if (options.TryGetTypeInfo(typeof(Order), out _))
    Console.WriteLine("  Metadata available for Order");
else
    Console.WriteLine($"✘ No metadata for Order — resolver doesn't cover it (no exception thrown)");

// ── Types ────────────────────────────────────────────────────────
public record Person(string Name, int Age);
public record Order(int Id, decimal Total);   // deliberately not registered

[JsonSerializable(typeof(Person))]
internal partial class AppJsonContext : JsonSerializerContext;

